    /**
     * Resend.
     * @throws Throwable exception if occurs.
     */
    @Test
    public void testTestResend() throws Exception {
        // Parameters for the API call
        String quickInvoiceId = 
                "11e95f8ec39de8fbdb0a4f1a";
        List<String> expand = null;
        EmailEnum email = null;
        SmsEnum sms = null;

        // Set callback and perform API call
        ResponseQuickInvoiceResend result = null;
        try {
            result = controller.resend(quickInvoiceId, expand, email, sms);
        } catch (ApiException e) {
            // Empty block
        }

        // Test whether the response is null
        assertNotNull("Response is null", 
                httpResponse.getResponse());
        // Test response code
        assertEquals("Status is not 201", 
                201, httpResponse.getResponse().getStatusCode());

        // Test headers
        Map<String, String> headers = new LinkedHashMap<String, String>();
        headers.put("Content-Type", "application/json");
        
        assertTrue("Headers do not match", TestHelper.areHeadersProperSubsetOf(
                headers, httpResponse.getResponse().getHeaders().asSimpleMap(), true));

        // Test whether the captured response is as we expected
        assertNotNull("Result does not exist", 
                result);
        assertTrue("Response body does not match in keys", 
                TestHelper.isJsonObjectProperSubsetOf(
                "{\"type\":\"QuickInvoiceResend\",\"data\":{\"id\":\"11e95f8ec39de8fbdb0a4f1a\",\"e"
                + "mail_log_id\":\"11e95f8ec39de8fbdb0a4f1a\",\"sms_log_id\":\"11e95f8ec39de8fbdb0a"
                + "4f1a\",\"success\":true,\"sms_success\":true,\"email\":\"email@domain.com\"}}",
                TestHelper.convertStreamToString(httpResponse.getResponse().getRawBody()), 
                false, true, false));
    }

